SELECT amino_acid_sequence
FROM tcr_sequences
WHERE is_public = 1;

SELECT AVG(frequency) AS average_frequency
FROM tcr_sequences
WHERE species = 'Homo sapiens';

SELECT COUNT(*) AS public_sequence_count
FROM tcr_sequences
WHERE is_public = 1;

SELECT COUNT(DISTINCT sequence_id) AS unique_sequence_count
FROM tcr_sequences
WHERE target = 'Epstein-Barr Virus';

SELECT amino_acid_sequence
FROM tcr_sequences
WHERE frequency = (SELECT MAX(frequency) FROM tcr_sequences);

SELECT amino_acid_sequence, frequency
FROM tcr_sequences
WHERE sequence_id = 1;
